package com.example.kafkaproducer;

import org.apache.kafka.clients.producer.KafkaProducer;
import org.apache.kafka.clients.producer.ProducerRecord;
import org.apache.kafka.common.header.internals.RecordHeader;
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestHeader;
import org.springframework.web.bind.annotation.RestController;

import jakarta.annotation.PostConstruct;
import jakarta.annotation.PreDestroy;
import java.util.Map;
import java.util.Properties;
import java.util.concurrent.ExecutionException;
import java.util.concurrent.Future;
import org.apache.kafka.clients.producer.RecordMetadata;
import org.springframework.beans.factory.annotation.Value;

@SpringBootApplication
@RestController
public class KafkaProducerApplication {

    @Value("${kafka.bootstrap.servers}")
    private String bootstrapServers;

    @Value("${kafka.topic.name}")
    private String topicName;

    private KafkaProducer<String, String> producer;

    public static void main(String[] args) {
        SpringApplication.run(KafkaProducerApplication.class, args);
    }

    @PostConstruct
    public void initProducer() {
        Properties props = new Properties();
        props.put("bootstrap.servers", bootstrapServers);
        props.put("key.serializer", "org.apache.kafka.common.serialization.StringSerializer");
        props.put("value.serializer", "org.apache.kafka.common.serialization.StringSerializer");
        // Optional: Acks for message durability
        props.put("acks", "all");
        // Optional: Retries in case of producer failures
        props.put("retries", 3);
        // Optional: Batch size and linger.ms for efficiency
        props.put("batch.size", 16384);
        props.put("linger.ms", 10);

        this.producer = new KafkaProducer<>(props);
        System.out.println("Kafka Producer initialized with bootstrap servers: " + bootstrapServers);
    }

    @PreDestroy
    public void closeProducer() {
        if (producer != null) {
            producer.close();
            System.out.println("Kafka Producer closed.");
        }
    }

    @PostMapping("/produce")
    public ResponseEntity<String> produceMessage(
            @RequestBody String message,
            @RequestHeader(value = "tracking-id", required = false) String trackingId,
            @RequestHeader(value = "user-id", required = false) String userId,
            @RequestHeader Map<String, String> allHeaders // Catch all other headers
    ) {
        String key = "event-key-" + System.currentTimeMillis(); // Example key

        ProducerRecord<String, String> record = new ProducerRecord<>(topicName, key, message);

        // Add standard headers
        if (trackingId != null) {
            record.headers().add(new RecordHeader("tracking-id", trackingId.getBytes()));
        }
        if (userId != null) {
            record.headers().add(new RecordHeader("user-id", userId.getBytes()));
        }

        // Add custom headers from HTTP request that are not explicitly handled
        allHeaders.forEach((headerName, headerValue) -> {
            // Avoid re-adding or internal headers, case-insensitive check
            String lowerCaseHeaderName = headerName.toLowerCase();
            if (!lowerCaseHeaderName.equals("tracking-id") &&
                !lowerCaseHeaderName.equals("user-id") &&
                !lowerCaseHeaderName.startsWith("content-") && // typically not useful for Kafka headers
                !lowerCaseHeaderName.startsWith("host") &&
                !lowerCaseHeaderName.startsWith("user-agent") &&
                !lowerCaseHeaderName.startsWith("accept") &&
                !lowerCaseHeaderName.startsWith("connection")) {
                record.headers().add(new RecordHeader(headerName, headerValue.getBytes()));
            }
        });

        try {
            Future<RecordMetadata> future = producer.send(record);
            RecordMetadata metadata = future.get(); // Synchronous send for simplicity in example
            System.out.println("Message sent successfully to topic " + metadata.topic() +
                               ", partition " + metadata.partition() +
                               ", offset " + metadata.offset() +
                               ", with headers: " + record.headers());
            return ResponseEntity.ok("Message sent with custom headers: " + record.headers().toString());
        } catch (InterruptedException | ExecutionException e) {
            System.err.println("Error sending message to Kafka: " + e.getMessage());
            e.printStackTrace();
            return ResponseEntity.status(500).body("Error sending message: " + e.getMessage());
        }
    }
}